def rrf_merge(engine_results, k=60):
    # engine_results: list of lists (rank ordered)
    scores = {}
    for results in engine_results:
        for rank, doc_id in enumerate(results, 1):
            scores[doc_id] = scores.get(doc_id, 0) + (1.0 / (k + rank))

    # Sort final results by RRF score
    return sorted(scores.items(), key=lambda x: x[1], reverse=True)

# Mock results from 2 engines
e1 = ['doc_a', 'doc_b', 'doc_c']
e2 = ['doc_b', 'doc_c', 'doc_d']

merged = rrf_merge([e1, e2])
print(f"Merged Ranking (ID, RRF Score): {merged[:3]}")
